		if( $dvprint) $templateCode = str_replace('<%%VALUE(contact_number_of_person)%%>', safe_html($urow['contact_number_of_person']), $templateCode);
		if(!$dvprint) $templateCode = str_replace('<%%VALUE(contact_number_of_person)%%>', html_attr($row['contact_number_of_person']), $templateCode);
